import{_ as s,o as e,c as i,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Workflows y Jobs en Databricks","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/databricks/03-workflows-y-jobs.md","filePath":"data-engineering/databricks/03-workflows-y-jobs.md","lastUpdated":1782521464000}'),t={name:"data-engineering/databricks/03-workflows-y-jobs.md"};function r(n,a,l,c,d,p){return e(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="workflows-y-jobs-en-databricks" tabindex="-1">Workflows y Jobs en Databricks <a class="header-anchor" href="#workflows-y-jobs-en-databricks" aria-label="Permalink to &quot;Workflows y Jobs en Databricks&quot;">​</a></h1><p>Databricks Workflows permite automatizar notebooks, scripts, pipelines y tareas de datos. Es una pieza clave para pasar de análisis interactivo a procesos productivos.</p><h2 id="conceptos-clave" tabindex="-1">Conceptos clave <a class="header-anchor" href="#conceptos-clave" aria-label="Permalink to &quot;Conceptos clave&quot;">​</a></h2><ul><li><strong>Job:</strong> definición de una ejecución automatizada.</li><li><strong>Task:</strong> unidad individual dentro de un job.</li><li><strong>Workflow:</strong> conjunto de tareas relacionadas.</li><li><strong>Schedule:</strong> programación temporal.</li><li><strong>Cluster de job:</strong> clúster creado para una ejecución concreta.</li><li><strong>Parámetro:</strong> valor configurable que se pasa a una tarea.</li></ul><h2 id="cuando-usar-workflows" tabindex="-1">Cuándo usar Workflows <a class="header-anchor" href="#cuando-usar-workflows" aria-label="Permalink to &quot;Cuándo usar Workflows&quot;">​</a></h2><p>Úsalo cuando necesites:</p><ul><li>Ejecutar notebooks de forma programada.</li><li>Encadenar tareas dependientes.</li><li>Automatizar cargas diarias.</li><li>Ejecutar validaciones de calidad.</li><li>Publicar tablas analíticas.</li></ul><h2 id="estructura-de-un-workflow" tabindex="-1">Estructura de un workflow <a class="header-anchor" href="#estructura-de-un-workflow" aria-label="Permalink to &quot;Estructura de un workflow&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ingesta -&gt; validación -&gt; transformación -&gt; publicación -&gt; notificación</span></span></code></pre></div><p>Cada paso puede ser una task independiente.</p><h2 id="parametros-en-notebooks" tabindex="-1">Parámetros en notebooks <a class="header-anchor" href="#parametros-en-notebooks" aria-label="Permalink to &quot;Parámetros en notebooks&quot;">​</a></h2><p>Los widgets permiten parametrizar notebooks.</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dbutils.widgets.text(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;fecha&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fecha </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dbutils.widgets.get(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;fecha&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Esto facilita reutilizar el mismo notebook en distintos días o entornos.</p><h2 id="buenas-practicas" tabindex="-1">Buenas prácticas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas prácticas&quot;">​</a></h2><ul><li>Divide workflows en tareas pequeñas.</li><li>Usa parámetros para fechas, rutas y entornos.</li><li>Separa notebooks exploratorios de notebooks productivos.</li><li>Configura alertas ante fallos.</li><li>Registra métricas de filas procesadas.</li><li>Usa clusters de job para procesos recurrentes.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Ejecutar notebooks manuales como si fueran pipelines productivos.</li><li>No parametrizar fechas o rutas.</li><li>No definir notificaciones de fallo.</li><li>Mezclar exploración, limpieza y publicación en una sola tarea enorme.</li><li>No documentar dependencias entre tareas.</li></ul><h2 id="chuleta-rapida" tabindex="-1">Chuleta rápida <a class="header-anchor" href="#chuleta-rapida" aria-label="Permalink to &quot;Chuleta rápida&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Job = ejecución automatizada</span></span>
<span class="line"><span>Task = paso del job</span></span>
<span class="line"><span>Schedule = programación</span></span>
<span class="line"><span>Parameter = valor configurable</span></span>
<span class="line"><span>Job cluster = cómputo por ejecución</span></span></code></pre></div><h2 id="recursos-relacionados" tabindex="-1">Recursos relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos relacionados&quot;">​</a></h2><ul><li><a href="./01-databricks">Databricks: introducción</a></li><li><a href="./02-notebooks">Notebooks</a></li><li><a href="./../pipelines/01-introduccion">Pipelines de datos</a></li></ul>`,22)])])}const k=s(t,[["render",r]]);export{h as __pageData,k as default};
